/**
 * Embedded report fonts (Fraunces display serif + Inter text), subset to Latin
 * and base64-encoded so the exported PDF carries its own typography with no
 * network fetch. Registered on a jsPDF doc via registerReportFonts(). Each
 * weight is its own family name so drawing code selects it by name, style
 * "normal", side-stepping jsPDF/normal/bold mapping.
 *
 * Generated from Google Fonts Fraunces + Inter (OFL). Do not hand edit.
 */

import type jsPDF from "jspdf"

interface EmbeddedFont { readonly file: string; readonly family: string; readonly data: string }

const FONTS: readonly EmbeddedFont[] = [
  { file: "Fraunces-400.ttf", family: "FrauncesReg", data:
    "" },
  { file: "Fraunces-600.ttf", family: "FrauncesSemi", data:
    "" },
  { file: "Fraunces-900.ttf", family: "FrauncesBlack", data:
    "" },
  { file: "Inter-400.ttf", family: "Inter", data:
    "" },
  { file: "Inter-600.ttf", family: "InterSemi", data:
    "" },
  { file: "Inter-700.ttf", family: "InterBold", data:
    "" },
]

/** Font family names, so drawing code never hard-codes the strings. */
export const RF = {
  frauncesReg: "FrauncesReg",
  frauncesSemi: "FrauncesSemi",
  frauncesBlack: "FrauncesBlack",
  inter: "Inter",
  interSemi: "InterSemi",
  interBold: "InterBold",
} as const

let installedOnce = false

/** Add every embedded font to the doc VFS and register it (style "normal"). */
export function registerReportFonts(doc: jsPDF): void {
  for (const f of FONTS) {
    doc.addFileToVFS(f.file, f.data)
    doc.addFont(f.file, f.family, "normal")
  }
  installedOnce = true
}

export function reportFontsInstalled(): boolean {
  return installedOnce
}
